// ─────────────────────────────────────────────────────────
// Node: Parse Profiles & Generate Emails
// Reads SerpAPI results, calls Gemini once per profile,
// then returns a single aggregated payload for the callback.
// ─────────────────────────────────────────────────────────

const GEMINI_API_KEY = $vars.GEMINI_API_KEY;
const GEMINI_MODEL   = 'gemini-1.5-flash';
const MAX_PROFILES   = 10;

// ── Pull webhook data (body fields are spread directly into $json for webhook v2)
const webhookItem = $('Webhook').first().json;
const chatInput   = webhookItem.chatInput   ?? webhookItem.body?.chatInput;
const searchId    = webhookItem.searchId    ?? webhookItem.body?.searchId;
const callbackUrl = webhookItem.callbackUrl ?? webhookItem.body?.callbackUrl;

if (!searchId || !callbackUrl) {
  throw new Error('Missing searchId or callbackUrl in webhook payload');
}

// ── Pull SerpAPI organic results
const serpData      = $input.first().json;
const organicResults = serpData.organic_results ?? [];

if (organicResults.length === 0) {
  return [{ json: { searchId, callbackUrl, results: [] } }];
}

// ── Helper: extract name + company from a LinkedIn SERP title
// Typical title formats:
//   "John Doe - CTO at Acme Corp | LinkedIn"
//   "Jane Smith | VP of Engineering at Stripe"
function parseTitleDetails(title) {
  const clean = title.replace(/ \| LinkedIn$/, '').replace(/ - LinkedIn$/, '').trim();

  // Try "Name - Role at Company"
  const dashMatch = clean.match(/^(.+?) - .* at (.+)$/);
  if (dashMatch) {
    return { fullName: dashMatch[1].trim(), company: dashMatch[2].trim() };
  }

  // Try "Name | Role at Company"
  const pipeMatch = clean.match(/^(.+?) \| .* at (.+)$/);
  if (pipeMatch) {
    return { fullName: pipeMatch[1].trim(), company: pipeMatch[2].trim() };
  }

  // Fallback: everything before " - " or " | " is the name
  const namePart = clean.split(/ - | \| /)[0].trim();
  return { fullName: namePart, company: '' };
}

// ── Process each profile
const results = [];

for (const result of organicResults.slice(0, MAX_PROFILES)) {
  const title       = result.title   ?? '';
  const linkedinUrl = result.link    ?? '';
  const context     = result.snippet ?? '';

  const { fullName, company } = parseTitleDetails(title);
  const nameParts = fullName.split(' ');
  const firstName = nameParts[0] ?? '';
  const lastName  = nameParts.slice(1).join(' ');

  // ── Call Gemini to write the cold email
  let emailSubject = '';
  let emailBody    = '';

  try {
    const prompt = [
      'You are a world-class cold email copywriter. Write a short, highly personalized cold outreach email.',
      '',
      `Search Context (what the sender is looking for): ${chatInput}`,
      `Prospect Name: ${firstName} ${lastName}`,
      `Prospect Company / Role: ${company}`,
      `LinkedIn Snippet: ${context}`,
      `LinkedIn URL: ${linkedinUrl}`,
      '',
      'Return ONLY valid JSON — no markdown, no code fences, no explanation:',
      '{',
      '  "email_subject": "...",',
      '  "email_body": "..."',
      '}',
      '',
      'Constraints:',
      '- Subject: ≤ 60 characters, specific and intriguing, no "Quick question" clichés',
      '- Body: 80–130 words, opens with a hyper-specific observation about the prospect',
      '- No openers like "Hope this finds you well" or "I came across your profile"',
      '- End with one soft, clear call to action (e.g., "Open to a 15-min chat next week?")',
      '- First-person, conversational, zero jargon',
    ].join('\n');

    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_API_KEY}`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          contents: [{ parts: [{ text: prompt }] }],
          generationConfig: { temperature: 0.75, maxOutputTokens: 512 },
        }),
      }
    );

    const data    = await res.json();
    const rawText = data.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}';
    const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed  = JSON.parse(cleaned);

    emailSubject = parsed.email_subject ?? '';
    emailBody    = parsed.email_body    ?? '';

  } catch (err) {
    // Graceful fallback so one failure doesn't break the whole batch
    emailSubject = `${firstName}, quick thought`;
    emailBody    = [
      `Hi ${firstName},`,
      '',
      `I was looking for ${chatInput} and your background${company ? ` at ${company}` : ''} stood out immediately.`,
      '',
      'Would you be open to a quick 15-minute call? I think there could be a genuinely interesting fit.',
      '',
      'Best,',
    ].join('\n');
  }

  results.push({
    linkedin_url:  linkedinUrl,
    first_name:    firstName,
    last_name:     lastName,
    domain_name:   company,
    context,
    email:         '',
    email_subject: emailSubject,
    email_body:    emailBody,
  });
}

return [{ json: { searchId, callbackUrl, results } }];
